// frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// --- Leaflet race guard patch ---
if (typeof L !== "undefined" && L.TileLayer && !L.TileLayer.__raceGuardPatched) {
  const T = L.TileLayer.prototype;
  const _tileReady = T._tileReady;
  const _tileOnError = T._tileOnError;

  T._tileReady = function (tile, err, ...rest) {
    if (!this._map) return;
    return _tileReady.call(this, tile, err, ...rest);
  };

  T._tileOnError = function (ev) {
    if (!this._map) return;
    return _tileOnError.call(this, ev);
  };

  L.TileLayer.__raceGuardPatched = true;
}

// --- Safe remove helper ---
function safeRemoveTileLayer(map, layer) {
  if (!layer) return;
  try {
    layer.off();
    if (typeof layer._abortLoading === "function") layer._abortLoading();
    if (layer._container) layer._container.innerHTML = "";
  } catch {}
  try {
    if (map && map.hasLayer(layer)) map.removeLayer(layer);
  } catch {}
}

export default function Radar() {
  const mapRef = useRef(null);
  const overlayRef = useRef(null);
  const [provider, setProvider] = useState("auto");

  const OWM_KEY = process.env.REACT_APP_OWM_KEY || "";
  const CENTER = [33.749, -84.388]; // Atlanta

  // Base maps
  const baseMaps = {
    osm: L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      attribution:
        '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
    }),
    dark: L.tileLayer(
      "https://tiles.stadiamaps.com/tiles/alidade_dark/{z}/{x}/{y}{r}.png",
      { attribution: "&copy; Stadia Maps" }
    ),
  };

  // Overlay providers
  const overlays = {
    owm_rain: L.tileLayer(
      `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`,
      { opacity: 0.6 }
    ),
    owm_snow: L.tileLayer(
      `https://tile.openweathermap.org/map/snow_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`,
      { opacity: 0.6 }
    ),
    rainviewer: L.tileLayer(
      "https://tilecache.rainviewer.com/v2/radar/{time}/256/{z}/{x}/{y}/2/1_1.png",
      { opacity: 0.6 }
    ),
  };

  useEffect(() => {
    // Initialize map
    const map = L.map("radar-map", {
      center: CENTER,
      zoom: 6,
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
      fadeAnimation: false,
      zoomAnimation: false,
    });
    mapRef.current = map;

    baseMaps.osm.addTo(map);

    // Choose overlay
    let chosenOverlay;
    if (provider === "auto") {
      chosenOverlay = overlays.owm_rain; // default auto choice
    } else if (overlays[provider]) {
      chosenOverlay = overlays[provider];
    }

    if (chosenOverlay) {
      overlayRef.current = chosenOverlay;
      chosenOverlay.addTo(map);
    }

    return () => {
      safeRemoveTileLayer(map, overlayRef.current);
      map.remove();
      mapRef.current = null;
    };
  }, [provider]); // re-run when provider changes

  return (
    <div className="w-full h-full flex flex-col">
      {/* Provider selector */}
      <div className="flex gap-2 p-2 bg-black bg-opacity-50 text-white">
        <button onClick={() => setProvider("auto")}>Auto</button>
        <button onClick={() => setProvider("owm_rain")}>Rain</button>
        <button onClick={() => setProvider("owm_snow")}>Snow</button>
        <button onClick={() => setProvider("rainviewer")}>RainViewer</button>
      </div>

      {/* Map container */}
      <div id="radar-map" className="flex-1 w-full h-full" />
    </div>
  );
}
